import { Dirty } from "../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js";
import * as fs from "fs";
import * as os from "os";
import * as path from "path";

describe("Dirty close() with pending queue", () => {
  it("should eventually close the write stream after draining pending writes", (done) => {
    const tmpFile = path.join(os.tmpdir(), `dirty-test-close-${process.pid}.db`);

    const db = new Dirty(tmpFile);

    const cleanup = () => {
      try { fs.unlinkSync(tmpFile); } catch (e) { /* ignore */ }
    };

    db.on("load", () => {
      // Add items to the queue
      db.set("key1", { value: "test1" });
      db.set("key2", { value: "test2" });

      // Call close() while items are in the queue.
      // Original: listens on 'drain', then closes -> write_close fires
      // Mutant: listens on '', which never fires -> write_close never fires
      db.close();

      const timer = setTimeout(() => {
        cleanup();
        done(new Error("Timed out: close() never completed, likely due to mutation"));
      }, 3000);

      db.once("write_close", () => {
        clearTimeout(timer);
        cleanup();
        done();
      });
    });
  });
});
